package org.example.userservice.controller;

import org.example.userservice.config.SecurityConfigTest;
import org.example.userservice.controllers.AuthController;
import org.example.userservice.dto.LoginResponse;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.services.AuthService;
import org.example.userservice.services.EmailVerificationService;
import org.example.userservice.services.PasswordResetService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.context.annotation.Import;
import org.springframework.data.jpa.mapping.JpaMetamodelMappingContext;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.test.web.servlet.MockMvc;

import static org.mockito.Mockito.doNothing;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(AuthController.class)
@Import(SecurityConfigTest.class)
@DisplayName("AuthController Web Layer Tests")
class AuthControllerTest {

        @Autowired
        private MockMvc mockMvc;

        @MockitoBean
        private AuthService authService;

        @MockitoBean
        private EmailVerificationService emailVerificationService;

        @MockitoBean
        private PasswordResetService passwordResetService;

        @MockitoBean
        private JpaMetamodelMappingContext jpaMetamodelMappingContext;

        private String validUserJson() {
                return """
                                {
                                  "firstname":"John",
                                  "lastname":"Doe",
                                  "email":"john@example.com",
                                  "password":"StrongPass1!"
                                }
                                """;
        }

        // Protects public auth endpoints behavior, validation, and service error
        // translation.
        @Nested
        @DisplayName("Authentication endpoints")
        class AuthenticationEndpoints {

                @Test
                @DisplayName("should register user and return 201")
                void shouldRegister() throws Exception {
                        doNothing().when(authService).register(org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/register")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content(validUserJson()))
                                        .andExpect(status().isCreated())
                                        .andExpect(jsonPath("$.success").value(true))
                                        .andExpect(jsonPath("$.message").value("Verification email sent"));

                        verify(authService).register(org.mockito.ArgumentMatchers.any());
                }

                @Test
                @DisplayName("should return 400 when register body is invalid")
                void shouldReturnBadRequestOnInvalidRegisterBody() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/register")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{" +
                                                        "\"firstname\":\"\"," +
                                                        "\"lastname\":\"\"," +
                                                        "\"email\":\"bad\"," +
                                                        "\"password\":\"weak\"" +
                                                        "}"))
                                        .andExpect(status().isBadRequest());

                        verifyNoInteractions(authService);
                }

                @Test
                @DisplayName("should login and return access token in response body")
                void shouldLogin() throws Exception {
                        when(authService.login(org.mockito.ArgumentMatchers.any(), org.mockito.ArgumentMatchers.any()))
                                        .thenReturn(new LoginResponse("access-token"));

                        mockMvc.perform(post("/api/v1/auth/login")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("""
                                                        {
                                                          "email":"john@example.com",
                                                          "password":"StrongPass1!"
                                                        }
                                                        """))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.success").value(true))
                                        .andExpect(jsonPath("$.data.access_token").value("access-token"));
                }

                @Test
                @DisplayName("should return 401 when refresh token cookie is missing")
                void shouldReturnUnauthorizedWhenRefreshCookieMissing() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/refresh-token"))
                                        .andExpect(status().isUnauthorized());

                        verifyNoInteractions(authService);
                }

                @Test
                @DisplayName("should verify email token and return 200")
                void shouldVerifyEmail() throws Exception {
                        doNothing().when(emailVerificationService).confirmToken("token-123");

                        mockMvc.perform(post("/api/v1/auth/verify-email")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"token\":\"token-123\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Email verified successfully"));

                        verify(emailVerificationService).confirmToken("token-123");
                }

                @Test
                @DisplayName("should return token valid=true when password reset token is valid")
                void shouldReturnValidTokenResult() throws Exception {
                        when(passwordResetService.validateToken("token-123")).thenReturn(true);

                        mockMvc.perform(post("/api/v1/auth/validate-password-reset-token")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"token\":\"token-123\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.data").value(true))
                                        .andExpect(jsonPath("$.message").value("Token valid"));
                }

                @Test
                @DisplayName("should return 400 when forgot-password body is invalid")
                void shouldReturnBadRequestForInvalidForgotPasswordBody() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/forgot-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"email\":\"\"}"))
                                        .andExpect(status().isBadRequest());

                        verifyNoInteractions(passwordResetService);
                }

                @Test
                @DisplayName("should translate service custom exception for reset-password")
                void shouldTranslateServiceErrorForResetPassword() throws Exception {
                        org.mockito.Mockito.doThrow(new CustomException("Token expired", HttpStatus.BAD_REQUEST))
                                        .when(passwordResetService).resetPassword(org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/reset-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("""
                                                        {
                                                          "token":"expired-token",
                                                          "newPassword":"StrongPass1!"
                                                        }
                                                        """))
                                        .andExpect(status().isBadRequest())
                                        .andExpect(jsonPath("$.message").value("Token expired"));
                }
        }
}

package org.example.userservice.controller;

import org.example.userservice.config.SecurityConfigTest;
import org.example.userservice.controllers.AuthController;
import org.example.userservice.dto.LoginResponse;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.services.AuthService;
import org.example.userservice.services.EmailVerificationService;
import org.example.userservice.services.PasswordResetService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.context.annotation.Import;
import org.springframework.data.jpa.mapping.JpaMetamodelMappingContext;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.test.web.servlet.MockMvc;

import jakarta.servlet.http.Cookie;

import static org.mockito.Mockito.doNothing;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(AuthController.class)
@Import(SecurityConfigTest.class)
@DisplayName("AuthController Web Layer Tests")
class AuthControllerTest {

        @Autowired
        private MockMvc mockMvc;

        @MockitoBean
        private AuthService authService;

        @MockitoBean
        private EmailVerificationService emailVerificationService;

        @MockitoBean
        private PasswordResetService passwordResetService;

        @MockitoBean
        private JpaMetamodelMappingContext jpaMetamodelMappingContext;

        private String validUserJson() {
                return """
                                {
                                  "firstname":"John",
                                  "lastname":"Doe",
                                  "email":"john@example.com",
                                  "password":"StrongPass1!"
                                }
                                """;
        }

        // Protects public auth endpoints behavior, validation, and service error
        // translation.
        @Nested
        @DisplayName("Authentication endpoints")
        class AuthenticationEndpoints {

                @Test
                @DisplayName("should register user and return 201")
                void shouldRegister() throws Exception {
                        doNothing().when(authService).register(org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/register")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content(validUserJson()))
                                        .andExpect(status().isCreated())
                                        .andExpect(jsonPath("$.success").value(true))
                                        .andExpect(jsonPath("$.message").value("Verification email sent"));

                        verify(authService).register(org.mockito.ArgumentMatchers.any());
                }

                @Test
                @DisplayName("should return 400 when register body is invalid")
                void shouldReturnBadRequestOnInvalidRegisterBody() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/register")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{" +
                                                        "\"firstname\":\"\"," +
                                                        "\"lastname\":\"\"," +
                                                        "\"email\":\"bad\"," +
                                                        "\"password\":\"weak\"" +
                                                        "}"))
                                        .andExpect(status().isBadRequest());

                        verifyNoInteractions(authService);
                }

                @Test
                @DisplayName("should login and return access token in response body")
                void shouldLogin() throws Exception {
                        when(authService.login(org.mockito.ArgumentMatchers.any(), org.mockito.ArgumentMatchers.any()))
                                        .thenReturn(new LoginResponse("access-token"));

                        mockMvc.perform(post("/api/v1/auth/login")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("""
                                                        {
                                                          "email":"john@example.com",
                                                          "password":"StrongPass1!"
                                                        }
                                                        """))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.success").value(true))
                                        .andExpect(jsonPath("$.data.access_token").value("access-token"));
                }

                @Test
                @DisplayName("should return 401 when refresh token cookie is missing")
                void shouldReturnUnauthorizedWhenRefreshCookieMissing() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/refresh-token"))
                                        .andExpect(status().isUnauthorized());

                        verifyNoInteractions(authService);
                }

                @Test
                @DisplayName("should verify email token and return 200")
                void shouldVerifyEmail() throws Exception {
                        doNothing().when(emailVerificationService).confirmToken("token-123");

                        mockMvc.perform(post("/api/v1/auth/verify-email")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"token\":\"token-123\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Email verified successfully"));

                        verify(emailVerificationService).confirmToken("token-123");
                }

                @Test
                @DisplayName("should return token valid=true when password reset token is valid")
                void shouldReturnValidTokenResult() throws Exception {
                        when(passwordResetService.validateToken("token-123")).thenReturn(true);

                        mockMvc.perform(post("/api/v1/auth/validate-password-reset-token")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"token\":\"token-123\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.data").value(true))
                                        .andExpect(jsonPath("$.message").value("Token valid"));
                }

                @Test
                @DisplayName("should return 400 when forgot-password body is invalid")
                void shouldReturnBadRequestForInvalidForgotPasswordBody() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/forgot-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"email\":\"\"}"))
                                        .andExpect(status().isBadRequest());

                        verifyNoInteractions(passwordResetService);
                }

                @Test
                @DisplayName("should translate service custom exception for reset-password")
                void shouldTranslateServiceErrorForResetPassword() throws Exception {
                        org.mockito.Mockito.doThrow(new CustomException("Token expired", HttpStatus.BAD_REQUEST))
                                        .when(passwordResetService).resetPassword(org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/reset-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("""
                                                        {
                                                          "token":"expired-token",
                                                          "newPassword":"StrongPass1!"
                                                        }
                                                        """))
                                        .andExpect(status().isBadRequest())
                                        .andExpect(jsonPath("$.message").value("Token expired"));
                }

                @Test
                @DisplayName("should refresh access token when refresh cookie is present")
                void shouldRefreshTokenWhenCookiePresent() throws Exception {
                        when(authService.refresh(org.mockito.ArgumentMatchers.eq("refresh-cookie"), org.mockito.ArgumentMatchers.any()))
                                        .thenReturn(new LoginResponse("new-access-token"));

                        mockMvc.perform(post("/api/v1/auth/refresh-token")
                                        .cookie(new Cookie("REFRESH_TOKEN", "refresh-cookie")))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Access token refreshed"))
                                        .andExpect(jsonPath("$.data.access_token").value("new-access-token"));

                        verify(authService).refresh(org.mockito.ArgumentMatchers.eq("refresh-cookie"), org.mockito.ArgumentMatchers.any());
                }

                @Test
                @DisplayName("should logout successfully even when refresh cookie is absent")
                void shouldLogoutSuccessfully() throws Exception {
                        doNothing().when(authService).logout(org.mockito.ArgumentMatchers.isNull(), org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/logout"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Logged out successfully"));

                        verify(authService).logout(org.mockito.ArgumentMatchers.isNull(), org.mockito.ArgumentMatchers.any());
                }

                @Test
                @DisplayName("should resend verification email for valid request")
                void shouldResendVerification() throws Exception {
                        doNothing().when(emailVerificationService)
                                        .resendVerification(new org.example.userservice.dto.ResendVerificationRequest("john@example.com"));

                        mockMvc.perform(post("/api/v1/auth/resend-verification")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"email\":\"john@example.com\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Verification email resent"));

                        verify(emailVerificationService)
                                        .resendVerification(new org.example.userservice.dto.ResendVerificationRequest("john@example.com"));
                }

                @Test
                @DisplayName("should return 400 when resend-verification body is invalid")
                void shouldReturnBadRequestForInvalidResendVerificationBody() throws Exception {
                        mockMvc.perform(post("/api/v1/auth/resend-verification")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"email\":\"bad-email\"}"))
                                        .andExpect(status().isBadRequest());

                        verifyNoInteractions(emailVerificationService);
                }

                @Test
                @DisplayName("should return token valid=false for invalid email verification token")
                void shouldReturnInvalidEmailVerificationTokenResult() throws Exception {
                        when(emailVerificationService.validateToken("token-123")).thenReturn(false);

                        mockMvc.perform(post("/api/v1/auth/validate-email-verification-token")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"token\":\"token-123\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.data").value(false))
                                        .andExpect(jsonPath("$.message").value("Token invalid"));
                }

                @Test
                @DisplayName("should create forgot-password request for valid body")
                void shouldCreateForgotPasswordRequest() throws Exception {
                        doNothing().when(passwordResetService).createAndSendResetToken("john@example.com");

                        mockMvc.perform(post("/api/v1/auth/forgot-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("{\"email\":\"john@example.com\"}"))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("A password reset link has been sent"));

                        verify(passwordResetService).createAndSendResetToken("john@example.com");
                }

                @Test
                @DisplayName("should reset password successfully")
                void shouldResetPasswordSuccessfully() throws Exception {
                        doNothing().when(passwordResetService).resetPassword(org.mockito.ArgumentMatchers.any());

                        mockMvc.perform(post("/api/v1/auth/reset-password")
                                        .contentType(MediaType.APPLICATION_JSON)
                                        .content("""
                                                        {
                                                          "token":"valid-token",
                                                          "newPassword":"StrongPass1!"
                                                        }
                                                        """))
                                        .andExpect(status().isOk())
                                        .andExpect(jsonPath("$.message").value("Password reset successfully"));

                        verify(passwordResetService).resetPassword(org.mockito.ArgumentMatchers.any());
                }
        }
}

package org.example.userservice.exceptions;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.ConstraintViolationException;
import org.example.userservice.dto.ApiResponse;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.core.MethodParameter;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.security.core.AuthenticationException;
import org.springframework.validation.BeanPropertyBindingResult;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.context.request.ServletWebRequest;

import java.lang.reflect.Method;
import java.util.Collections;
import java.util.NoSuchElementException;
import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

@DisplayName("GlobalExceptionHandler Unit Tests")
class GlobalExceptionHandlerTest {

    private final GlobalExceptionHandler handler = new GlobalExceptionHandler();

    // Protects API-level exception-to-status translation rules.
    @Nested
    @DisplayName("Exception mappings")
    class ExceptionMappings {

        @Test
        @DisplayName("should map CustomException 4xx as-is")
        void shouldMapCustomException4xx() {
            ResponseEntity<ApiResponse<?>> response = handler.handleCustomException(
                    new CustomException("Bad input", HttpStatus.BAD_REQUEST)
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().success()).isFalse();
            assertThat(response.getBody().message()).isEqualTo("Bad input");
        }

        @Test
        @DisplayName("should map CustomException 5xx as-is")
        void shouldMapCustomException5xx() {
            ResponseEntity<ApiResponse<?>> response = handler.handleCustomException(
                    new CustomException("System down", HttpStatus.INTERNAL_SERVER_ERROR)
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("System down");
        }

        @Test
        @DisplayName("should map data integrity error containing Email to 422")
        void shouldMapEmailDataIntegrityTo422() {
            ResponseEntity<ApiResponse<?>> response = handler.handleDataIntegrityViolationException(
                    new DataIntegrityViolationException("Email must be unique")
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.UNPROCESSABLE_ENTITY);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).contains("Email");
        }

        @Test
        @DisplayName("should map non-email data integrity error to 409")
        void shouldMapNonEmailDataIntegrityTo409() {
            ResponseEntity<ApiResponse<?>> response = handler.handleDataIntegrityViolationException(
                    new DataIntegrityViolationException("duplicate key value violates unique constraint")
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.CONFLICT);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).contains("duplicate key");
        }

        @Test
        @DisplayName("should map authentication errors to 401 and WWW-Authenticate header")
        void shouldMapAuthenticationException() {
            ResponseEntity<ApiResponse<?>> response = handler.handleAuthenticationException(
                    new AuthenticationException("Bad credentials") {
                    }
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.UNAUTHORIZED);
            assertThat(response.getHeaders().getFirst(HttpHeaders.WWW_AUTHENTICATE)).isEqualTo("Bearer");
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("Unauthorized");
        }

        @Test
        @DisplayName("should map access denied to 403")
        void shouldMapAccessDenied() {
            ResponseEntity<ApiResponse<?>> response = handler.handleAccessDenied(
                    new AccessDeniedException("forbidden")
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.FORBIDDEN);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("Access denied");
        }

        @Test
        @DisplayName("should map no-such-element to 404")
        void shouldMapNotFound() {
            ResponseEntity<ApiResponse<?>> response = handler.handleNotFound(
                    new NoSuchElementException("missing")
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.NOT_FOUND);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("Resource not found");
        }

        @Test
        @DisplayName("should map illegal argument to 400")
        void shouldMapIllegalArgument() {
            ResponseEntity<ApiResponse<?>> response = handler.handleIllegalArgument(
                    new IllegalArgumentException("invalid state")
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("invalid state");
        }

        @Test
        @DisplayName("should map fallback exception to 500")
        void shouldMapFallbackException() {
            ResponseEntity<ApiResponse<?>> response = handler.handleAll(new RuntimeException("boom"));

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("Internal server error");
        }
    }

    // Protects validation and malformed payload error body contract.
    @Nested
    @DisplayName("Validation handlers")
    class ValidationHandlers {

        @Test
        @DisplayName("should return field-level map for method argument validation failures")
        void shouldMapMethodArgumentNotValid() throws Exception {
            Method method = TestInput.class.getDeclaredMethod("accept", String.class);
            MethodParameter methodParameter = new MethodParameter(method, 0);
            BeanPropertyBindingResult bindingResult = new BeanPropertyBindingResult(new Object(), "request");
            bindingResult.addError(new FieldError("request", "email", "must be a well-formed email address"));
            MethodArgumentNotValidException ex = new MethodArgumentNotValidException(methodParameter, bindingResult);

            ResponseEntity<Object> response = handler.handleMethodArgumentNotValid(
                    ex,
                    new HttpHeaders(),
                    HttpStatus.BAD_REQUEST,
                    new ServletWebRequest(new MockHttpServletRequest())
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isInstanceOf(ApiResponse.class);
            ApiResponse<?> body = (ApiResponse<?>) response.getBody();
            assertThat(body.message()).isEqualTo("Validation failed");
            assertThat(body.errors()).containsKey("email");
        }

        @Test
        @DisplayName("should map malformed body to generic message")
        void shouldMapMalformedBody() {
            ResponseEntity<Object> response = handler.handleHttpMessageNotReadable(
                    new HttpMessageNotReadableException("Invalid JSON"),
                    new HttpHeaders(),
                    HttpStatus.BAD_REQUEST,
                    new ServletWebRequest(new MockHttpServletRequest())
            );

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isInstanceOf(ApiResponse.class);
            ApiResponse<?> body = (ApiResponse<?>) response.getBody();
            assertThat(body.message()).isEqualTo("Malformed request body");
        }

        @Test
        @DisplayName("should use first constraint violation message")
        void shouldMapConstraintViolationMessage() {
            @SuppressWarnings("unchecked")
            ConstraintViolation<Object> violation = mock(ConstraintViolation.class);
            when(violation.getMessage()).thenReturn("email is invalid");

            ConstraintViolationException ex = new ConstraintViolationException(Set.of(violation));
            ResponseEntity<ApiResponse<?>> response = handler.handleConstraintViolation(ex);

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("email is invalid");
        }

        @Test
        @DisplayName("should use default constraint violation message when none exist")
        void shouldMapConstraintViolationFallback() {
            ConstraintViolationException ex = new ConstraintViolationException("none", Collections.emptySet());

            ResponseEntity<ApiResponse<?>> response = handler.handleConstraintViolation(ex);

            assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
            assertThat(response.getBody()).isNotNull();
            assertThat(response.getBody().message()).isEqualTo("Constraint violation");
        }
    }

    private static class TestInput {
        @SuppressWarnings("unused")
        void accept(String email) {
            // Method exists only to create a MethodParameter for validation error construction.
        }
    }
}

package org.example.userservice.security;

import org.example.userservice.config.SecurityConfig;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.context.annotation.Import;
import org.springframework.data.jpa.mapping.JpaMetamodelMappingContext;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors;
import org.springframework.test.context.TestPropertySource;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.time.Instant;
import java.util.List;
import java.util.Map;

import static org.assertj.core.api.Assertions.assertThat;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(SecurityConfigCoverageTest.ProbeController.class)
@Import(SecurityConfig.class)
@TestPropertySource(properties = "jwt.secret=12345678901234567890123456789012")
@DisplayName("SecurityConfig Coverage Tests")
class SecurityConfigCoverageTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private org.springframework.core.convert.converter.Converter<Jwt, ? extends AbstractAuthenticationToken> jwtAuthenticationConverter;

    @MockitoBean
    private JpaMetamodelMappingContext jpaMetamodelMappingContext;

    // Protects route-level access rules configured in SecurityFilterChain.
    @Nested
    @DisplayName("route authorization")
    class RouteAuthorization {

        @Test
        @DisplayName("should return 401 for unauthenticated protected route")
        void shouldReturnUnauthorizedForProtectedRoute() throws Exception {
            mockMvc.perform(get("/internal/secured"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should allow unauthenticated GET by-email route")
        void shouldAllowPublicGetByEmail() throws Exception {
            mockMvc.perform(get("/api/v1/users/by-email"))
                    .andExpect(status().isOk());
        }

        @Test
        @DisplayName("should allow unauthenticated GET user by id route")
        void shouldAllowPublicGetById() throws Exception {
            mockMvc.perform(get("/api/v1/users/11111111-1111-1111-1111-111111111111"))
                    .andExpect(status().isOk());
        }

        @Test
        @DisplayName("should deny DELETE for authenticated USER role")
        void shouldDenyDeleteForUserRole() throws Exception {
            mockMvc.perform(delete("/api/v1/users/11111111-1111-1111-1111-111111111111")
                            .with(SecurityMockMvcRequestPostProcessors.jwt()
                                    .jwt(jwt -> jwt.claim("roles", java.util.List.of("ROLE_USER")))))
                    .andExpect(status().isForbidden());
        }

        @Test
        @DisplayName("should deny DELETE when JWT has no roles claim")
        void shouldDenyDeleteWhenRolesMissing() throws Exception {
            mockMvc.perform(delete("/api/v1/users/11111111-1111-1111-1111-111111111111")
                            .with(SecurityMockMvcRequestPostProcessors.jwt()))
                    .andExpect(status().isForbidden());
        }

        @Test
        @DisplayName("should allow DELETE for ADMIN role")
        void shouldAllowDeleteForAdminRole() throws Exception {
            mockMvc.perform(delete("/api/v1/users/11111111-1111-1111-1111-111111111111")
                            .with(SecurityMockMvcRequestPostProcessors.jwt()
                                    .authorities(new SimpleGrantedAuthority("ROLE_ADMIN"))))
                    .andExpect(status().isOk());
        }

        @Test
        @DisplayName("should allow PUT for USER role")
        void shouldAllowPutForUserRole() throws Exception {
            mockMvc.perform(put("/api/v1/users/11111111-1111-1111-1111-111111111111")
                            .with(SecurityMockMvcRequestPostProcessors.jwt()
                                    .authorities(new SimpleGrantedAuthority("ROLE_USER"))))
                    .andExpect(status().isOk());
        }
    }

    // Protects JWT roles claim conversion used by resource-server authentication.
    @Nested
    @DisplayName("jwt authority conversion")
    class JwtAuthorityConversion {

        @Test
        @DisplayName("should convert roles claim into granted authorities")
        void shouldConvertRolesClaim() {
            Jwt jwt = new Jwt(
                    "token",
                    Instant.now(),
                    Instant.now().plusSeconds(300),
                    Map.of("alg", "none"),
                    Map.of("roles", List.of("ROLE_ADMIN"))
            );

            AbstractAuthenticationToken auth = jwtAuthenticationConverter.convert(jwt);

            assertThat(auth).isNotNull();
            assertThat(auth.getAuthorities())
                    .extracting(Object::toString)
                    .contains("ROLE_ADMIN");
        }

        @Test
        @DisplayName("should return empty authorities when roles claim is missing")
        void shouldReturnEmptyAuthoritiesWhenRolesMissing() {
            Jwt jwt = new Jwt(
                    "token",
                    Instant.now(),
                    Instant.now().plusSeconds(300),
                    Map.of("alg", "none"),
                    Map.of("sub", "user-1")
            );

            AbstractAuthenticationToken auth = jwtAuthenticationConverter.convert(jwt);

            assertThat(auth).isNotNull();
            assertThat(auth.getAuthorities()).isEmpty();
        }
    }

    @RestController
    @RequestMapping
    static class ProbeController {

        @GetMapping("/internal/secured")
        ResponseEntity<Void> secured() {
            return ResponseEntity.ok().build();
        }

        @GetMapping("/api/v1/users/by-email")
        ResponseEntity<Void> byEmail() {
            return ResponseEntity.ok().build();
        }

        @GetMapping("/api/v1/users/{id}")
        ResponseEntity<Void> byId(@PathVariable String id) {
            return ResponseEntity.ok().build();
        }

        @DeleteMapping("/api/v1/users/{id}")
        ResponseEntity<Void> deleteUser(@PathVariable String id) {
            return ResponseEntity.ok().build();
        }

        @PutMapping("/api/v1/users/{id}")
        ResponseEntity<Void> updateUser(@PathVariable String id) {
            return ResponseEntity.ok().build();
        }
    }
}

package org.example.userservice.security;

import org.example.userservice.config.VerifiedUserChecker;
import org.example.userservice.exceptions.CustomException;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.security.authentication.TestingAuthenticationToken;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationToken;

import java.time.Instant;
import java.util.List;
import java.util.Map;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

@DisplayName("VerifiedUserChecker Unit Tests")
class VerifiedUserCheckerTest {

    private final VerifiedUserChecker checker = new VerifiedUserChecker();

    private JwtAuthenticationToken jwtAuth(List<String> roles, Boolean verified) {
        Jwt jwt = new Jwt(
                "token",
                Instant.now(),
                Instant.now().plusSeconds(300),
                Map.of("alg", "none"),
                Map.of("roles", roles, "verified", verified)
        );
        return new JwtAuthenticationToken(jwt);
    }

    // Protects authorization rule: only JWT auth is accepted.
    @Nested
    @DisplayName("authentication type")
    class AuthenticationType {

        @Test
        @DisplayName("should reject non-JWT authentication")
        void shouldRejectNonJwtAuthentication() {
            assertThatThrownBy(() -> checker.isVerified(new TestingAuthenticationToken("user", "pass")))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("Invalid authentication token")
                    .extracting(ex -> ((CustomException) ex).getStatus())
                    .isEqualTo(HttpStatus.UNAUTHORIZED);
        }
    }

    // Protects verification policy for admin bypass and regular users.
    @Nested
    @DisplayName("verification policy")
    class VerificationPolicy {

        @Test
        @DisplayName("should bypass verification for admin roles")
        void shouldBypassForAdminRole() {
            boolean result = checker.isVerified(jwtAuth(List.of("ROLE_ADMIN"), false));

            assertThat(result).isTrue();
        }

        @Test
        @DisplayName("should allow verified regular user")
        void shouldAllowVerifiedRegularUser() {
            boolean result = checker.isVerified(jwtAuth(List.of("ROLE_USER"), true));

            assertThat(result).isTrue();
        }

        @Test
        @DisplayName("should reject unverified regular user")
        void shouldRejectUnverifiedRegularUser() {
            assertThatThrownBy(() -> checker.isVerified(jwtAuth(List.of("ROLE_USER"), false)))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("Email not verified")
                    .extracting(ex -> ((CustomException) ex).getStatus())
                    .isEqualTo(HttpStatus.FORBIDDEN);
        }
    }
}

package org.example.userservice.service;

import jakarta.mail.Session;
import jakarta.mail.internet.MimeMessage;
import org.example.userservice.dto.ResendVerificationRequest;
import org.example.userservice.entities.EmailVerificationToken;
import org.example.userservice.entities.User;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.repositories.EmailVerificationTokenRepository;
import org.example.userservice.repositories.UserRepository;
import org.example.userservice.services.EmailVerificationService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.http.HttpStatus;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.test.util.ReflectionTestUtils;
import org.thymeleaf.spring6.SpringTemplateEngine;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.time.Instant;
import java.util.HexFormat;
import java.util.Optional;
import java.util.UUID;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.Mockito.inOrder;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
@DisplayName("EmailVerificationService Unit Tests")
class EmailVerificationServiceTest {

    @Mock
    private EmailVerificationTokenRepository tokenRepository;
    @Mock
    private UserRepository userRepository;
    @Mock
    private JavaMailSender mailSender;
    @Mock
    private SpringTemplateEngine templateEngine;

    @InjectMocks
    private EmailVerificationService emailVerificationService;

    private User buildUser(String email, boolean verified) {
        return User.builder()
                .id(UUID.randomUUID())
                .firstname("John")
                .lastname("Doe")
                .email(email)
                .password("encoded")
                .verified(verified)
                .build();
    }

    private void setFields() {
        ReflectionTestUtils.setField(emailVerificationService, "tokenTtlHours", 24L);
        ReflectionTestUtils.setField(emailVerificationService, "appName", "Collabri");
        ReflectionTestUtils.setField(emailVerificationService, "supportEmail", "support@collabri.com");
        ReflectionTestUtils.setField(emailVerificationService, "mailFrom", "noreply@collabri.com");
        ReflectionTestUtils.setField(emailVerificationService, "frontendVerifyUrl", "https://frontend/verify-email");
    }

    private String sha256(String raw) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            return HexFormat.of().formatHex(digest.digest(raw.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Protects token issuance and resend hygiene for unverified accounts.
    @Nested
    @DisplayName("createAndSendVerificationToken()")
    class CreateAndSendVerificationToken {

        @Test
        @DisplayName("should cleanup old tokens, persist new token, and send verification email")
        void shouldCreateAndSendToken() {
            setFields();
            User user = buildUser("verify@example.com", false);
            MimeMessage message = new MimeMessage((Session) null);

            when(userRepository.findByEmail("verify@example.com")).thenReturn(Optional.of(user));
            when(templateEngine.process(org.mockito.ArgumentMatchers.eq("verify-email"), org.mockito.ArgumentMatchers.any()))
                    .thenReturn("<html>ok</html>");
            when(mailSender.createMimeMessage()).thenReturn(message);

            emailVerificationService.createAndSendVerificationToken("verify@example.com");

            verify(tokenRepository).deleteAllByUser(user);
            ArgumentCaptor<EmailVerificationToken> captor = ArgumentCaptor.forClass(EmailVerificationToken.class);
            verify(tokenRepository).save(captor.capture());
            assertThat(captor.getValue().getTokenHash()).hasSize(64);
            assertThat(captor.getValue().isUsed()).isFalse();
            verify(mailSender).send(message);
        }

        @Test
        @DisplayName("should throw BAD_REQUEST when user is already verified")
        void shouldThrowWhenAlreadyVerified() {
            User user = buildUser("already@example.com", true);
            when(userRepository.findByEmail("already@example.com")).thenReturn(Optional.of(user));

            assertThatThrownBy(() -> emailVerificationService.createAndSendVerificationToken("already@example.com"))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("User already verified")
                    .extracting(ex -> ((CustomException) ex).getStatus())
                    .isEqualTo(HttpStatus.BAD_REQUEST);

            verifyNoInteractions(tokenRepository, mailSender);
        }
    }

    // Protects verification confirmation branches and state transitions.
    @Nested
    @DisplayName("confirmToken()")
    class ConfirmToken {

        @Test
        @DisplayName("should verify user, mark token used, and cleanup all user tokens")
        void shouldConfirmSuccessfully() {
            String raw = "confirm-token";
            String hash = sha256(raw);
            User user = buildUser("confirm@example.com", false);
            EmailVerificationToken token = new EmailVerificationToken();
            token.setUser(user);
            token.setTokenHash(hash);
            token.setUsed(false);
            token.setExpiresAt(Instant.now().plusSeconds(60));

            when(tokenRepository.findByTokenHash(hash)).thenReturn(Optional.of(token));

            emailVerificationService.confirmToken(raw);

            assertThat(user.isVerified()).isTrue();
            assertThat(token.isUsed()).isTrue();
            var order = inOrder(userRepository, tokenRepository);
            order.verify(userRepository).save(user);
            order.verify(tokenRepository).save(token);
            order.verify(tokenRepository).deleteAllByUser(user);
        }

        @Test
        @DisplayName("should throw BAD_REQUEST when token is blank")
        void shouldThrowWhenTokenBlank() {
            assertThatThrownBy(() -> emailVerificationService.confirmToken("  "))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("Invalid token")
                    .extracting(ex -> ((CustomException) ex).getStatus())
                    .isEqualTo(HttpStatus.BAD_REQUEST);

            verifyNoInteractions(tokenRepository);
        }
    }

    // Protects resend endpoint from account enumeration leaks.
    @Nested
    @DisplayName("resendVerification()")
    class ResendVerification {

        @Test
        @DisplayName("should silently swallow user-not-found and not throw")
        void shouldSwallowUserNotFound() {
            when(userRepository.findByEmail("missing@example.com")).thenReturn(Optional.empty());

            emailVerificationService.resendVerification(new ResendVerificationRequest("missing@example.com"));

            verifyNoInteractions(tokenRepository, mailSender);
        }
    }

    // Protects frontend helper validation behavior.
    @Nested
    @DisplayName("validateToken()")
    class ValidateToken {

        @Test
        @DisplayName("should return true when token is valid")
        void shouldReturnTrueWhenValid() {
            String raw = "valid-token";
            String hash = sha256(raw);
            EmailVerificationToken token = new EmailVerificationToken();
            token.setUsed(false);
            token.setExpiresAt(Instant.now().plusSeconds(60));
            when(tokenRepository.findByTokenHash(hash)).thenReturn(Optional.of(token));

            assertThat(emailVerificationService.validateToken(raw)).isTrue();
        }

        @Test
        @DisplayName("should throw BAD_REQUEST when token is already used")
        void shouldThrowWhenUsed() {
            String raw = "used-token";
            String hash = sha256(raw);
            EmailVerificationToken token = new EmailVerificationToken();
            token.setUsed(true);
            token.setExpiresAt(Instant.now().plusSeconds(60));
            when(tokenRepository.findByTokenHash(hash)).thenReturn(Optional.of(token));

            assertThatThrownBy(() -> emailVerificationService.validateToken(raw))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("Token already used")
                    .extracting(ex -> ((CustomException) ex).getStatus())
                    .isEqualTo(HttpStatus.BAD_REQUEST);
        }
    }
}

package org.example.userservice.service;

import jakarta.mail.Session;
import jakarta.mail.internet.MimeMessage;
import org.example.userservice.dto.ResendVerificationRequest;
import org.example.userservice.entities.EmailVerificationToken;
import org.example.userservice.entities.User;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.repositories.EmailVerificationTokenRepository;
import org.example.userservice.repositories.UserRepository;
import org.example.userservice.services.EmailVerificationService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.http.HttpStatus;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.test.util.ReflectionTestUtils;
import org.thymeleaf.spring6.SpringTemplateEngine;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.time.Instant;
import java.util.HexFormat;
import java.util.Optional;
import java.util.UUID;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.inOrder;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
@DisplayName("EmailVerificationService Unit Tests")
class EmailVerificationServiceTest {

    @Mock
    private EmailVerificationTokenRepository tokenRepository;
    @Mock
    private UserRepository userRepository;
    @Mock
    private JavaMailSender mailSender;
    @Mock
    private SpringTemplateEngine templateEngine;

    @InjectMocks
    private EmailVerificationService emailVerificationService;

    private User buildUser(String email, boolean verified) {
        return User.builder()
                .id(UUID.randomUUID())
                .firstname("John")
                .lastname("Doe")
                .email(email)
                .password("encoded")
                .verified(verified)
                .build();
    }

    private void setFields() {
        ReflectionTestUtils.setField(emailVerificationService, "tokenTtlHours", 24L);
        ReflectionTestUtils.setField(emailVerificationService, "appName", "Collabri");
        ReflectionTestUtils.setField(emailVerificationService, "supportEmail", "support@collabri.com");
        ReflectionTestUtils.setField(emailVerificationService, "mailFrom", "noreply@collabri.com");
        ReflectionTestUtils.setField(emailVerificationService, "frontendVerifyUrl", "https://frontend/verify-email");
    }

    private String sha256(String raw) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            return HexFormat.of().formatHex(digest.digest(raw.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Protects token issuance and resend hygiene for unverified accounts.
    @Nested
    @DisplayName("createAndSendVerificationToken()")
    class CreateAndSendVerificationToken {

        @Test
        @DisplayName("should cleanup old tokens, persist new token, and send verification email")
        void shouldCreateAndSendToken() {
            setFields();
            User user = buildUser("verify@example.com", false);
            MimeMessage message = new MimeMessage((Session) null);

            when(userRepository.findByEmail("verify@example.com")).thenReturn(Optional.of(user));
            when(templateEngine.process(org.mockito.ArgumentMatchers.eq("verify-email"), org.mockito.ArgumentMatchers.any()))
                    .thenReturn("<html>ok</html>");
            when(mailSender.createMimeMessage()).thenReturn(message);

            emailVerificationService.createAndSendVerificationToken("verify@example.com");

            verify(tokenRepository).deleteAllByUser(user);
            ArgumentCaptor<EmailVerificationToken> captor = ArgumentCaptor.forClass(EmailVerificationToken.class);
            verify(tokenRepository).save(captor.capture());
            assertThat(captor.getValue().getTokenHash()).hasSize(64);
            assertThat(captor.getValue().isUsed()).isFalse();
            verify(mailSender).send(message);
        }

        @Test
        @DisplayName("should throw BAD_REQUEST when user is already verified")
        void shouldThrowWhenAlreadyVerified() {
            User user = buildUser("already@example.com", true);
            when(userRepository.findByEmail("already@example.com")).thenReturn(Optional.of(user));

            assertThatThrownBy(() -> emailVerificationService.createAndSendVerificationToken("already@example.com"))
